from flask import Flask, request, jsonify
from itsdangerous import TimedJSONWebToken as TJWT

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your-secret-key'
jwt = TJWT(app.config['SECRET_KEY'])

@app.route('/login', methods=['POST'])
def login():
    username = request.json.get('username')
    password = request.json.get('password')
    if username == 'your-username' and password == 'your-password':
        token = jwt.dumps({'user_id': 1})
        return jsonify({'token': token}), 200
    else:
        return jsonify({'error': 'Invalid credentials'}), 403

@app.route('/protected', methods=['GET'])
def protected():
    if request.headers.get('Authorization') is None:
        return jsonify({'error': 'Token not provided'}), 401
    try:
        token = request.headers.get('Authorization').replace('Bearer ', '')
        payload = jwt.loads(token)
        if payload['user_id'] == 1:
            return jsonify({'message': 'You have access to the protected resource'}), 200
        else:
            return jsonify({'error': 'Invalid token'}), 403
    except:
        return jsonify({'error': 'Invalid token'}), 403